(window.webpackJsonp=window.webpackJsonp||[]).push([[790],{782:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">k</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> findMinFibonacciNumbers = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">k</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> f=[<span class=\\"hljs-number\\">1</span>,<span class=\\"hljs-number\\">1</span>]\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">2</span>;i&lt;=<span class=\\"hljs-number\\">50</span>;i++){\\n      f[i]=f[i<span class=\\"hljs-number\\">-1</span>]+f[i<span class=\\"hljs-number\\">-2</span>]\\n  }\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">bsFront</span>(<span class=\\"hljs-params\\">arr,n</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> lo=<span class=\\"hljs-number\\">0</span>,hi=arr.length<span class=\\"hljs-number\\">-1</span>\\n    <span class=\\"hljs-keyword\\">while</span>(lo&lt;hi){\\n      <span class=\\"hljs-keyword\\">let</span> mid=<span class=\\"hljs-built_in\\">Math</span>.ceil((lo+hi)/<span class=\\"hljs-number\\">2</span>)\\n      <span class=\\"hljs-keyword\\">if</span>(arr[mid]&gt;n)hi=mid<span class=\\"hljs-number\\">-1</span>\\n      <span class=\\"hljs-keyword\\">else</span> lo=mid\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> lo\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">1</span>\\n  <span class=\\"hljs-keyword\\">let</span> x=k\\n  <span class=\\"hljs-keyword\\">while</span>(!f.includes(x)){\\n    <span class=\\"hljs-keyword\\">let</span> idx=bsFront(f,x)\\n    x-=f[idx]\\n    res++\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n};\\n\\n</code></pre>\\n"],"titleSlug":"find-the-minimum-number-of-fibonacci-numbers-whose-sum-is-k","hasThinking":false,"content":"<p>\u7ed9\u4f60\u6570\u5b57 <code>k</code>&nbsp;\uff0c\u8bf7\u4f60\u8fd4\u56de\u548c\u4e3a&nbsp;<code>k</code>&nbsp;\u7684\u6590\u6ce2\u90a3\u5951\u6570\u5b57\u7684\u6700\u5c11\u6570\u76ee\uff0c\u5176\u4e2d\uff0c\u6bcf\u4e2a\u6590\u6ce2\u90a3\u5951\u6570\u5b57\u90fd\u53ef\u4ee5\u88ab\u4f7f\u7528\u591a\u6b21\u3002</p>\\n\\n<p>\u6590\u6ce2\u90a3\u5951\u6570\u5b57\u5b9a\u4e49\u4e3a\uff1a</p>\\n\\n<ul>\\n\\t<li>F<sub>1</sub> = 1</li>\\n\\t<li>F<sub>2</sub> = 1</li>\\n\\t<li>F<sub>n</sub> = F<sub>n-1</sub> + F<sub>n-2</sub>&nbsp;\uff0c \u5176\u4e2d n &gt; 2 \u3002</li>\\n</ul>\\n\\n<p>\u6570\u636e\u4fdd\u8bc1\u5bf9\u4e8e\u7ed9\u5b9a\u7684 <code>k</code>&nbsp;\uff0c\u4e00\u5b9a\u80fd\u627e\u5230\u53ef\u884c\u89e3\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>k = 7\\n<strong>\u8f93\u51fa\uff1a</strong>2 \\n<strong>\u89e3\u91ca\uff1a</strong>\u6590\u6ce2\u90a3\u5951\u6570\u5b57\u4e3a\uff1a1\uff0c1\uff0c2\uff0c3\uff0c5\uff0c8\uff0c13\uff0c&hellip;&hellip;\\n\u5bf9\u4e8e k = 7 \uff0c\u6211\u4eec\u53ef\u4ee5\u5f97\u5230 2 + 5 = 7 \u3002</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>k = 10\\n<strong>\u8f93\u51fa\uff1a</strong>2 \\n<strong>\u89e3\u91ca\uff1a</strong>\u5bf9\u4e8e k = 10 \uff0c\u6211\u4eec\u53ef\u4ee5\u5f97\u5230 2 + 8 = 10 \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>k = 19\\n<strong>\u8f93\u51fa\uff1a</strong>3 \\n<strong>\u89e3\u91ca\uff1a</strong>\u5bf9\u4e8e k = 19 \uff0c\u6211\u4eec\u53ef\u4ee5\u5f97\u5230 1 + 5 + 13 = 19 \u3002\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= k &lt;= 10^9</code></li>\\n</ul>\\n","title":"1414. \u548c\u4e3a K \u7684\u6700\u5c11\u6590\u6ce2\u90a3\u5951\u6570\u5b57\u6570\u76ee","relatedTags":["\u8d2a\u5fc3\u7b97\u6cd5","\u6570\u7ec4"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1414"}')}}]);